'use client';

import { useState } from 'react';

interface TerminalReplayProps {
  /** Path to a GIF or PNG relative to /public (e.g., "screenshots/plan-mode.gif") */
  src: string;
  /** Alt text for the image. Default: "Claude Code terminal" */
  alt?: string;
  /** Pixel height of the container. Default: auto (aspect ratio preserved) */
  height?: number;
}

/**
 * Renders a VHS-captured terminal GIF or PNG. GIFs auto-play as animated
 * terminal replays; PNGs show a static screenshot. Both are generated by
 * the `vhs` CLI tool from .tape script files in public/tapes/.
 *
 * Usage:
 *   <TerminalReplay src="screenshots/plan-mode.gif" />
 *   <TerminalReplay src="screenshots/first-launch.png" />
 */
export default function TerminalReplay({
  src,
  alt = 'Claude Code terminal',
  height,
}: TerminalReplayProps) {
  const [failed, setFailed] = useState(false);
  const isGif = src.endsWith('.gif');

  if (failed) {
    return (
      <div
        style={{
          background: '#1a1916',
          borderRadius: 12,
          padding: '32px 24px',
          textAlign: 'center',
          color: '#9a9589',
          fontFamily: 'var(--font-body)',
          fontSize: 13,
          height: height ?? 'auto',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        Terminal screenshot not available
      </div>
    );
  }

  return (
    <div
      style={{
        borderRadius: 12,
        overflow: 'hidden',
        border: '1px solid var(--color-border)',
        backgroundColor: '#1a1916',
        position: 'relative',
      }}
    >
      {/* GIF badge so users know it's animated */}
      {isGif && (
        <div
          style={{
            position: 'absolute',
            top: 10,
            right: 10,
            fontSize: 9,
            fontWeight: 700,
            fontFamily: 'var(--font-body)',
            textTransform: 'uppercase',
            letterSpacing: '0.08em',
            color: '#fff',
            backgroundColor: 'rgba(204, 92, 56, 0.85)',
            padding: '3px 8px',
            borderRadius: 6,
            zIndex: 1,
          }}
        >
          Live demo
        </div>
      )}
      {/* eslint-disable-next-line @next/next/no-img-element */}
      <img
        src={`/${src}`}
        alt={alt}
        onError={() => setFailed(true)}
        style={{
          display: 'block',
          width: '100%',
          height: height ?? 'auto',
          objectFit: 'contain',
        }}
      />
    </div>
  );
}
